import outlines
from outlines import prompts

prompts.register_filter('shout', lambda s: s.upper())

@outlines.prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

prompts.unregister_filter('shout')

try:
    @outlines.prompt
    def greet2(name):
        '''Hello {{ name | shout }}'''
    print('ERROR: should have raised')
except Exception as e:
    print('OK, raised after unregister:', type(e).__name__, e)

# built-in filters still take precedence
prompts.register_filter('name', lambda fn: 'OVERRIDDEN')
@outlines.prompt
def show_name(fn):
    '''{{ fn | name }}'''

def my_func():
    pass

print(show_name(my_func))
prompts.unregister_filter('name')
